def gen(rng, size):
    n = max(1, min(size, 300))
    vals = rng.sample(range(1, 50001), n)
    vals.sort()
    # build a balanced BST over sorted distinct values -> node objects as (val, li, ri)
    nodes = [None] * n
    for i, v in enumerate(vals):
        nodes[i] = [v, None, None]
    def build(lo, hi):
        if lo > hi:
            return -1
        mid = (lo + hi) // 2
        nodes[mid][1] = build(lo, mid - 1)
        nodes[mid][2] = build(mid + 1, hi)
        return mid
    root_idx = build(0, n - 1)
    # cut the tree into pieces of at most depth-1 (root + up to 2 children).
    # process top-down: a piece is a chosen node together with its children that
    # we decide to keep attached; cut points spawn new pieces.
    pieces = []
    # decide for each edge whether it is a cut (separating into another piece)
    keep = {}
    for i in range(n):
        for ch in (nodes[i][1], nodes[i][2]):
            if ch != -1:
                keep[(i, ch)] = rng.random() < 0.5
    visited = [False] * n
    def collect_piece(idx):
        # piece root = idx; include children only if edge kept; that's it (no grandchildren)
        visited[idx] = True
        v = nodes[idx][0]
        li = nodes[idx][1]
        ri = nodes[idx][2]
        lv = None
        rv = None
        children_roots = []
        if li != -1 and keep.get((idx, li)):
            lv = nodes[li][0]
            visited[li] = True
            for gc in (nodes[li][1], nodes[li][2]):
                if gc != -1:
                    children_roots.append(gc)
        elif li != -1:
            lv = nodes[li][0]  # leaf placeholder whose value is another piece's root
            children_roots.append(li)
        if ri != -1 and keep.get((idx, ri)):
            rv = nodes[ri][0]
            visited[ri] = True
            for gc in (nodes[ri][1], nodes[ri][2]):
                if gc != -1:
                    children_roots.append(gc)
        elif ri != -1:
            rv = nodes[ri][0]
            children_roots.append(ri)
        # build wire form (BFS level-order with nulls)
        if lv is None and rv is None:
            wire = [v]
        else:
            wire = [v, lv, rv]
        return wire, children_roots
    # BFS over piece roots starting from the true root
    queue = [root_idx]
    seen_roots = set()
    while queue:
        idx = queue.pop()
        if idx in seen_roots:
            continue
        seen_roots.add(idx)
        wire, ch_roots = collect_piece(idx)
        pieces.append(wire)
        for c in ch_roots:
            queue.append(c)
    rng.shuffle(pieces)
    # 40% of the time, perturb a value to (likely) make the merge invalid/impossible
    if pieces and rng.random() < 0.4:
        pi = rng.randrange(len(pieces))
        wi = rng.randrange(len(pieces[pi]))
        if pieces[pi][wi] is not None:
            pieces[pi][wi] = rng.randint(1, 50000)
    return [pieces]

