class Solution:
    def canMerge(self, trees):
        # Independent oracle: index by root, splice each matching leaf once,
        # then brute-force validate the assembled tree by in-order traversal.
        by_root = {}
        for t in trees:
            by_root[t.val] = t
        # leaf-value occurrences across all pieces (each piece has <=2 leaves)
        from collections import Counter
        leaf_count = Counter()
        for t in trees:
            for c in (t.left, t.right):
                if c is not None:
                    leaf_count[c.val] += 1
        # A leaf value may match at most one root, and a root matched as a leaf
        # more than once is impossible (root values unique, but a value could be
        # a leaf in two pieces).
        for v, cnt in leaf_count.items():
            if v in by_root and cnt > 1:
                return None
        # candidate top roots: roots that never appear as a leaf
        tops = [v for v in by_root if leaf_count.get(v, 0) == 0]
        if len(tops) != 1:
            return None
        top_val = tops[0]
        # iterative splice using a worklist, attaching pieces by reference
        root = by_root[top_val]
        consumed = {top_val}
        stack = [root]
        ok = True
        while stack:
            cur = stack.pop()
            for side in ('left', 'right'):
                child = getattr(cur, side)
                if child is None:
                    continue
                if child.left is None and child.right is None and child.val in by_root:
                    # this leaf names a piece root
                    piece = by_root[child.val]
                    if child.val in consumed:
                        ok = False
                        break
                    consumed.add(child.val)
                    setattr(cur, side, piece)
                    stack.append(piece)
                else:
                    stack.append(child)
            if not ok:
                break
        if not ok:
            return None
        if len(consumed) != len(trees):
            return None
        # validate strict BST via in-order, also count nodes
        order = []
        st = []
        node = root
        guard = 0
        limit = len(trees) * 4 + 10
        while st or node is not None:
            while node is not None:
                st.append(node)
                node = node.left
                guard += 1
                if guard > limit:
                    return None
            node = st.pop()
            order.append(node.val)
            node = node.right
        for i in range(1, len(order)):
            if order[i] <= order[i - 1]:
                return None
        return root

