class Solution:
    def canMerge(self, trees):
        from collections import Counter
        by_root = {t.val: t for t in trees}
        leaf_count = Counter()
        for t in trees:
            for c in (t.left, t.right):
                if c is not None:
                    leaf_count[c.val] += 1
        # find the unique top: a root not consumed as any leaf
        tops = [v for v in by_root if leaf_count.get(v, 0) == 0]
        if len(tops) != 1:
            return None
        top = by_root[tops[0]]
        consumed = {tops[0]}
        # splice leaves that name a known root, in place
        def attach(node):
            for side in ('left', 'right'):
                child = getattr(node, side)
                if child is None:
                    continue
                if child.left is None and child.right is None and child.val in by_root:
                    if child.val in consumed:
                        return False
                    consumed.add(child.val)
                    piece = by_root[child.val]
                    setattr(node, side, piece)
                    if not attach(piece):
                        return False
                else:
                    if not attach(child):
                        return False
            return True
        if not attach(top):
            return None
        if len(consumed) != len(trees):
            return None
        # validate strict BST with bounds
        def valid(node, lo, hi):
            if node is None:
                return True
            if not (lo < node.val < hi):
                return False
            return valid(node.left, lo, node.val) and valid(node.right, node.val, hi)
        import sys
        sys.setrecursionlimit(300000)
        if not valid(top, float('-inf'), float('inf')):
            return None
        return top

