var canMerge = function(trees) {
    const byRoot = new Map();
    for (const t of trees) byRoot.set(t.val, t);
    const leafCount = new Map();
    for (const t of trees) {
        for (const c of [t.left, t.right]) {
            if (c !== null) leafCount.set(c.val, (leafCount.get(c.val) || 0) + 1);
        }
    }
    const tops = [];
    for (const v of byRoot.keys()) {
        if (!(leafCount.get(v) > 0)) tops.push(v);
    }
    if (tops.length !== 1) return null;
    const top = byRoot.get(tops[0]);
    const consumed = new Set([tops[0]]);
    function attach(node) {
        for (const side of ['left', 'right']) {
            const child = node[side];
            if (child === null) continue;
            if (child.left === null && child.right === null && byRoot.has(child.val)) {
                if (consumed.has(child.val)) return false;
                consumed.add(child.val);
                const piece = byRoot.get(child.val);
                node[side] = piece;
                if (!attach(piece)) return false;
            } else {
                if (!attach(child)) return false;
            }
        }
        return true;
    }
    if (!attach(top)) return null;
    if (consumed.size !== trees.length) return null;
    function valid(node, lo, hi) {
        if (node === null) return true;
        if (!(lo < node.val && node.val < hi)) return false;
        return valid(node.left, lo, node.val) && valid(node.right, node.val, hi);
    }
    if (!valid(top, -Infinity, Infinity)) return null;
    return top;
};
